import React from 'react';
import { ExternalLink } from 'lucide-react';
import { useLocation, useNavigate } from 'react-router-dom';
import { cn } from '@/shared/components/ui/contracts/cn';
import { PaneControlTab } from '@/shared/components/PaneControlTab';
import { useSlidingPane } from '@/shared/hooks/useSlidingPane';
import { usePanes } from '@/shared/contexts/PanesContext';
import { useAuth } from '@/shared/contexts/AuthContext';
import { useProjectSelectionContext } from '@/shared/contexts/ProjectContext';
import { useToolSettings } from '@/shared/hooks/settings/useToolSettings';
import { Button } from '@/shared/components/ui/button';
import { isVideoEditorRoute } from '@/app/hooks/useVideoEditorRouteState';
import { SupabaseDataProvider } from '@/tools/video-editor/data/SupabaseDataProvider';
import { VideoEditorProvider } from '@/tools/video-editor/contexts/VideoEditorProvider';
import { useTimelinesList } from '@/tools/video-editor/hooks/useTimelinesList';
import { videoEditorSettings } from '@/tools/video-editor/settings/videoEditorDefaults';
import { VideoEditorShell } from '@/tools/video-editor/components/VideoEditorShell';

function useEditorPane() {
  const {
    isEditorPaneLocked,
    setIsEditorPaneLocked,
    setIsEditorPaneOpen,
    effectiveEditorPaneHeight,
    isShotsPaneLocked,
    shotsPaneWidth,
    isTasksPaneLocked,
    tasksPaneWidth,
    isGenerationsPaneLocked,
    isGenerationsPaneOpen,
    effectiveGenerationsPaneHeight,
  } = usePanes();

  const pane = useSlidingPane({
    side: 'top',
    isLocked: isEditorPaneLocked,
    onToggleLock: () => setIsEditorPaneLocked(!isEditorPaneLocked),
    onOpenChange: setIsEditorPaneOpen,
  });

  // When the generations pane is locked/open, reduce the editor pane height to avoid overlap
  const generationsOffset = (isGenerationsPaneLocked || isGenerationsPaneOpen) ? effectiveGenerationsPaneHeight : 0;
  const adjustedEditorPaneHeight = Math.max(200, effectiveEditorPaneHeight - generationsOffset);

  return {
    pane,
    effectiveEditorPaneHeight: adjustedEditorPaneHeight,
    isShotsPaneLocked,
    shotsPaneWidth,
    isTasksPaneLocked,
    tasksPaneWidth,
  };
}

const EditorPaneComponent: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { selectedProjectId } = useProjectSelectionContext();
  const { userId } = useAuth();
  const { settings, update } = useToolSettings(videoEditorSettings.id, {
    projectId: selectedProjectId ?? undefined,
    enabled: Boolean(selectedProjectId),
  });
  const timelines = useTimelinesList(selectedProjectId, userId);
  const {
    pane,
    effectiveEditorPaneHeight,
    isShotsPaneLocked,
    shotsPaneWidth,
    isTasksPaneLocked,
    tasksPaneWidth,
  } = useEditorPane();

  if (isVideoEditorRoute(location.pathname)) {
    return null;
  }

  const horizontalOffset =
    (isShotsPaneLocked ? shotsPaneWidth : 0) -
    (isTasksPaneLocked ? tasksPaneWidth : 0);
  const activeTimelineId = settings?.lastTimelineId ?? timelines.data?.[0]?.id ?? null;
  const provider = selectedProjectId && userId
    ? new SupabaseDataProvider({ projectId: selectedProjectId, userId })
    : null;
  const activeTimelineName = timelines.data?.find((timeline) => timeline.id === activeTimelineId)?.name ?? null;
  const createTimeline = async () => {
    const created = await timelines.createTimeline.mutateAsync('Main timeline');
    await update('project', { lastTimelineId: created.id });
    navigate(`/tools/video-editor?timeline=${created.id}`);
  };

  return (
    <>
      {/* Control tab */}
      <PaneControlTab
        position={{
          side: 'top',
          paneDimension: effectiveEditorPaneHeight,
          horizontalOffset,
        }}
        state={{ isLocked: pane.isLocked, isOpen: pane.isOpen }}
        handlers={{
          toggleLock: pane.toggleLock,
          openPane: pane.openPane,
          handlePaneEnter: pane.handlePaneEnter,
          handlePaneLeave: pane.handlePaneLeave,
        }}
        display={{
          paneTooltip: 'Open editor',
        }}
        actions={{
          thirdButton: {
            onClick: () => {
              if (activeTimelineId) {
                navigate(`/tools/video-editor?timeline=${activeTimelineId}`);
                return;
              }
              navigate('/tools/video-editor');
            },
            ariaLabel: 'Go to editor',
            tooltip: 'Go to editor',
            content: <ExternalLink className="h-4 w-4" />,
          },
        }}
      />

      {/* Pane surface */}
      <div
        {...pane.paneProps}
        data-testid="editor-pane"
        style={{
          height: `${effectiveEditorPaneHeight}px`,
          marginLeft: isShotsPaneLocked ? `${shotsPaneWidth}px` : '0px',
          marginRight: isTasksPaneLocked ? `${tasksPaneWidth}px` : '0px',
          zIndex: 59,
        }}
        className={cn(
          'fixed top-0 left-0 right-0 flex flex-col border-b border-border bg-background/95 shadow-xl backdrop-blur-sm transform transition-[margin,padding] duration-300 ease-smooth pointer-events-auto',
          pane.transformClass,
        )}
      >
        {provider && userId && activeTimelineId ? (
          <VideoEditorProvider dataProvider={provider} timelineId={activeTimelineId} timelineName={activeTimelineName} userId={userId}>
            <VideoEditorShell mode="compact" timelineId={activeTimelineId} onCreateTimeline={() => void createTimeline()} />
          </VideoEditorProvider>
        ) : (
          <div className="flex h-full items-center justify-center">
            <div className="rounded-xl border border-dashed border-border bg-card/70 p-6 text-center">
              <div className="text-sm font-medium text-foreground">No active timeline</div>
              <div className="mt-1 text-xs text-muted-foreground">Create one in the standalone editor or from this pane.</div>
              <div className="mt-4 flex justify-center gap-2">
                <Button type="button" size="sm" onClick={() => void createTimeline()} disabled={!selectedProjectId || !userId}>
                  Create timeline
                </Button>
                <Button type="button" size="sm" variant="outline" onClick={() => navigate('/tools/video-editor')}>
                  Open editor
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
};

export const EditorPane = React.memo(EditorPaneComponent);

import React, { createContext, useContext, useState, ReactNode, useCallback, useMemo } from 'react';
import { PANE_CONFIG } from '@/shared/config/panes';
import { usePaneLockPolicyState } from '@/shared/contexts/usePaneLockPolicyState';

interface PanesContextType {
  isGenerationsPaneLocked: boolean;
  setIsGenerationsPaneLocked: (isLocked: boolean) => void;
  isGenerationsPaneOpen: boolean;
  setIsGenerationsPaneOpen: (isOpen: boolean) => void;
  generationsPaneHeight: number;
  effectiveGenerationsPaneHeight: number;
  setGenerationsPaneHeight: (height: number) => void;

  isEditorPaneLocked: boolean;
  setIsEditorPaneLocked: (isLocked: boolean) => void;
  isEditorPaneOpen: boolean;
  setIsEditorPaneOpen: (isOpen: boolean) => void;
  editorPaneHeight: number;
  effectiveEditorPaneHeight: number;

  isShotsPaneLocked: boolean;
  setIsShotsPaneLocked: (isLocked: boolean) => void;
  shotsPaneWidth: number;
  setShotsPaneWidth: (width: number) => void;

  isTasksPaneLocked: boolean;
  setIsTasksPaneLocked: (isLocked: boolean) => void;
  tasksPaneWidth: number;
  setTasksPaneWidth: (width: number) => void;

  // Active task tracking for highlighting
  activeTaskId: string | null;
  setActiveTaskId: (taskId: string | null) => void;

  // Programmatic tasks pane control (desktop only)
  isTasksPaneOpen: boolean;
  setIsTasksPaneOpen: (isOpen: boolean) => void;

  // Reset all pane locks (used by ProductTour)
  resetAllPaneLocks: () => void;
}

type PaneLockPolicyContextType = Pick<
  PanesContextType,
  | 'isGenerationsPaneLocked'
  | 'setIsGenerationsPaneLocked'
  | 'isGenerationsPaneOpen'
  | 'setIsGenerationsPaneOpen'
  | 'isEditorPaneLocked'
  | 'setIsEditorPaneLocked'
  | 'isEditorPaneOpen'
  | 'setIsEditorPaneOpen'
  | 'isShotsPaneLocked'
  | 'setIsShotsPaneLocked'
  | 'isTasksPaneLocked'
  | 'setIsTasksPaneLocked'
  | 'isTasksPaneOpen'
  | 'setIsTasksPaneOpen'
  | 'resetAllPaneLocks'
>;

type PaneLayoutContextType = Pick<
  PanesContextType,
  | 'generationsPaneHeight'
  | 'effectiveGenerationsPaneHeight'
  | 'setGenerationsPaneHeight'
  | 'editorPaneHeight'
  | 'effectiveEditorPaneHeight'
  | 'shotsPaneWidth'
  | 'setShotsPaneWidth'
  | 'tasksPaneWidth'
  | 'setTasksPaneWidth'
>;

type PaneSelectionContextType = Pick<
  PanesContextType,
  | 'activeTaskId'
  | 'setActiveTaskId'
>;

const PaneLockPolicyContext = createContext<PaneLockPolicyContextType | undefined>(undefined);
const PaneLayoutContext = createContext<PaneLayoutContextType | undefined>(undefined);
const PaneSelectionContext = createContext<PaneSelectionContextType | undefined>(undefined);

const MIN_EDITOR_HEIGHT = 200;

function getEffectivePaneHeights(params: {
  viewportHeight: number;
  idealEditorPaneHeight: number;
  generationsPaneHeight: number;
}) {
  const {
    viewportHeight,
    idealEditorPaneHeight,
    generationsPaneHeight,
  } = params;

  if (idealEditorPaneHeight + generationsPaneHeight <= viewportHeight) {
    return {
      effectiveEditorPaneHeight: idealEditorPaneHeight,
      effectiveGenerationsPaneHeight: generationsPaneHeight,
    };
  }

  if (viewportHeight >= generationsPaneHeight + MIN_EDITOR_HEIGHT) {
    return {
      effectiveEditorPaneHeight: viewportHeight - generationsPaneHeight,
      effectiveGenerationsPaneHeight: generationsPaneHeight,
    };
  }

  // Below the combined minimum, compress both panes while biasing toward editor space.
  // The denominator was derived from the degraded-tier test contract and keeps totals stable.
  const denom = 2 * (idealEditorPaneHeight + generationsPaneHeight) - viewportHeight;
  const effectiveGenerationsPaneHeight = Math.round((viewportHeight * generationsPaneHeight) / denom);

  return {
    effectiveEditorPaneHeight: Math.max(viewportHeight - effectiveGenerationsPaneHeight, 0),
    effectiveGenerationsPaneHeight,
  };
}

export const PanesProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const {
    locks,
    isGenerationsPaneOpenState,
    isEditorPaneOpenState,
    isTasksPaneOpenState,
    setIsGenerationsPaneLocked,
    setIsEditorPaneLocked,
    setIsShotsPaneLocked,
    setIsTasksPaneLocked,
    setIsGenerationsPaneOpen,
    setIsEditorPaneOpen,
    setIsTasksPaneOpen,
    resetAllPaneLocks,
  } = usePaneLockPolicyState();

  const viewportHeight = window.innerHeight;
  // Editor pane height = 90% of viewport when it has the viewport to itself
  const editorPaneHeight = Math.round(viewportHeight * 0.9);
  const editorVisible = locks.editor || isEditorPaneOpenState;
  const generationsVisible = locks.gens || isGenerationsPaneOpenState;

  // Pane dimensions (not persisted)
  const [generationsPaneHeight, setGenerationsPaneHeightState] = useState<number>(PANE_CONFIG.dimensions.DEFAULT_HEIGHT);
  const [shotsPaneWidth, setShotsPaneWidthState] = useState<number>(PANE_CONFIG.dimensions.DEFAULT_WIDTH);
  const [tasksPaneWidth, setTasksPaneWidthState] = useState<number>(PANE_CONFIG.dimensions.DEFAULT_WIDTH);

  // Active task tracking (not persisted)
  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);

  // Dimension setters
  const setGenerationsPaneHeight = useCallback((height: number) => {
    setGenerationsPaneHeightState(height);
  }, []);

  const setShotsPaneWidth = useCallback((width: number) => {
    setShotsPaneWidthState(width);
  }, []);

  const setTasksPaneWidth = useCallback((width: number) => {
    setTasksPaneWidthState(width);
  }, []);

  const { effectiveEditorPaneHeight, effectiveGenerationsPaneHeight } = getEffectivePaneHeights({
    viewportHeight,
    idealEditorPaneHeight: editorPaneHeight,
    generationsPaneHeight,
  });

  const lockPolicyValue = useMemo(
    (): PaneLockPolicyContextType => ({
      isGenerationsPaneLocked: locks.gens,
      setIsGenerationsPaneLocked,
      isGenerationsPaneOpen: isGenerationsPaneOpenState,
      setIsGenerationsPaneOpen,
      isEditorPaneLocked: locks.editor,
      setIsEditorPaneLocked,
      isEditorPaneOpen: isEditorPaneOpenState,
      setIsEditorPaneOpen,
      isShotsPaneLocked: locks.shots,
      setIsShotsPaneLocked,
      isTasksPaneLocked: locks.tasks,
      setIsTasksPaneLocked,
      isTasksPaneOpen: isTasksPaneOpenState,
      setIsTasksPaneOpen,
      resetAllPaneLocks,
    }),
    [
      locks.gens,
      locks.editor,
      locks.shots,
      locks.tasks,
      setIsGenerationsPaneLocked,
      isGenerationsPaneOpenState,
      setIsGenerationsPaneOpen,
      setIsEditorPaneLocked,
      isEditorPaneOpenState,
      setIsEditorPaneOpen,
      setIsShotsPaneLocked,
      setIsTasksPaneLocked,
      isTasksPaneOpenState,
      setIsTasksPaneOpen,
      resetAllPaneLocks,
    ]
  );

  const layoutValue = useMemo(
    (): PaneLayoutContextType => ({
      generationsPaneHeight,
      effectiveGenerationsPaneHeight,
      setGenerationsPaneHeight,
      editorPaneHeight,
      effectiveEditorPaneHeight,
      shotsPaneWidth,
      setShotsPaneWidth,
      tasksPaneWidth,
      setTasksPaneWidth,
    }),
    [
      generationsPaneHeight,
      effectiveGenerationsPaneHeight,
      setGenerationsPaneHeight,
      editorPaneHeight,
      effectiveEditorPaneHeight,
      shotsPaneWidth,
      setShotsPaneWidth,
      tasksPaneWidth,
      setTasksPaneWidth,
    ]
  );

  const selectionValue = useMemo(
    (): PaneSelectionContextType => ({
      activeTaskId,
      setActiveTaskId,
    }),
    [
      activeTaskId,
      setActiveTaskId,
    ]
  );

  return (
    <PaneLockPolicyContext.Provider value={lockPolicyValue}>
      <PaneLayoutContext.Provider value={layoutValue}>
        <PaneSelectionContext.Provider value={selectionValue}>
          {children}
        </PaneSelectionContext.Provider>
      </PaneLayoutContext.Provider>
    </PaneLockPolicyContext.Provider>
  );
};

export const usePanes = () => {
  const lockPolicy = useContext(PaneLockPolicyContext);
  const layout = useContext(PaneLayoutContext);
  const selection = useContext(PaneSelectionContext);

  if (!lockPolicy || !layout || !selection) {
    throw new Error('usePanes must be used within a PanesProvider');
  }

  return {
    ...lockPolicy,
    ...layout,
    ...selection,
  };
};

import type { CSSProperties } from 'react';
import { Outlet } from 'react-router-dom';
import { GlobalHeader } from '@/shared/components/GlobalHeader';
import { GlobalProcessingWarning } from '@/shared/components/ProcessingWarnings';
import { usePanes } from '@/shared/contexts/PanesContext';
import { useHeaderState } from '@/shared/contexts/ToolPageHeaderContext';
import { useViewportResponsive } from '@/shared/hooks/responsive/useViewportResponsive';
import { cn } from '@/shared/components/ui/contracts/cn';
import { useVideoEditorRouteState } from '@/app/hooks/useVideoEditorRouteState';

interface LayoutMainContentProps {
  isMobileSplitView: boolean;
  onOpenSettings: (initialTab?: string, creditsTab?: 'purchase' | 'history') => void;
}

export function LayoutMainContent(props: LayoutMainContentProps) {
  const { isMobileSplitView, onOpenSettings } = props;
  const { isVideoEditorShellActive } = useVideoEditorRouteState();
  const {
    isTasksPaneLocked,
    tasksPaneWidth,
    isShotsPaneLocked,
    shotsPaneWidth,
    isGenerationsPaneLocked,
    isGenerationsPaneOpen,
    effectiveGenerationsPaneHeight,
    isEditorPaneLocked,
    isEditorPaneOpen,
    effectiveEditorPaneHeight,
  } = usePanes();
  const { header } = useHeaderState();
  const { isSm, isMd, isLg, isXl, is2Xl, contentWidth, contentHeight } = useViewportResponsive();

  const containerPadding = isLg ? 'px-6' : isSm ? 'px-4' : 'px-2';
  const containerSpacing = 'py-1';

  const contentStyle = {
    marginRight: isVideoEditorShellActive ? '0px' : (isTasksPaneLocked ? `${tasksPaneWidth}px` : '0px'),
    marginLeft: isVideoEditorShellActive ? '0px' : (isShotsPaneLocked ? `${shotsPaneWidth}px` : '0px'),
    paddingTop: isVideoEditorShellActive ? '0px' : (isEditorPaneLocked ? `${effectiveEditorPaneHeight}px` : '0px'),
    paddingBottom: isMobileSplitView ? '0px' : ((isGenerationsPaneLocked || isGenerationsPaneOpen) ? `${effectiveGenerationsPaneHeight}px` : '0px'),
    '--content-width': `${contentWidth}px`,
    '--content-height': `${contentHeight}px`,
    '--content-sm': isSm ? '1' : '0',
    '--content-md': isMd ? '1' : '0',
    '--content-lg': isLg ? '1' : '0',
    '--content-xl': isXl ? '1' : '0',
    '--content-2xl': is2Xl ? '1' : '0',
    willChange: 'margin, padding',
  } as CSSProperties;

  return (
    <>
      {!isVideoEditorShellActive && (
        <GlobalHeader
          contentOffsetRight={isTasksPaneLocked ? tasksPaneWidth + 16 : 16}
          contentOffsetLeft={isShotsPaneLocked ? shotsPaneWidth : 0}
          onOpenSettings={onOpenSettings}
        />
      )}

      <div
        className={cn(
          'relative z-10 content-container',
          isVideoEditorShellActive
            ? 'h-screen w-screen overflow-hidden transition-[padding] duration-300 ease-smooth'
            : 'transition-[margin,padding] duration-300 ease-smooth',
        )}
        style={contentStyle}
      >
        {!isVideoEditorShellActive && <GlobalProcessingWarning onOpenSettings={onOpenSettings} />}

        <main
          className={cn(
            isVideoEditorShellActive
              ? 'h-full w-full overflow-hidden'
              : cn('container mx-auto', containerPadding, containerSpacing),
          )}
        >
          {!isVideoEditorShellActive && header}
          <Outlet />
        </main>
      </div>
    </>
  );
}

